export class OrderService {
  async createOrder(data) {
    const validated = this.validate(data);
    const order = await this.db.insert(validated);
    await this.emailClient.send(order.userEmail, 'Order confirmed');
    await this.metrics.increment('orders.created');
    return order;
  }

  validate(data) { /* ... */ }
}
